SELECT vr.*,
       rp.repair_plant_name,
       oe.enterprise_name,
       CASE WHEN vr.module_type = #{queryForm.vehicleModule}
       THEN v.vehicle_number ELSE b.bracket_no
       END AS vehicleNumber
FROM t_repair vr
LEFT JOIN t_repair_plant rp on rp.repair_plant_id  = vr.repair_plant_id
LEFT JOIN t_oa_enterprise oe ON vr.enterprise_id = oe.enterprise_id
LEFT JOIN t_vehicle v ON vr.module_id = v.vehicle_id and vr.module_type = #{queryForm.vehicleModule}
LEFT JOIN t_bracket b ON vr.module_id = b.bracket_id and vr.module_type = #{queryForm.bracketModule}
WHERE vr.deleted_flag = #{queryForm.deletedFlag}

    AND vr.enterprise_id = #{queryForm.enterpriseId}


    and vr.module_id = #{queryForm.moduleId}


    and vr.module_id in

        #{item}



    and vr.module_type = #{queryForm.moduleType}


    and vr.repair_plant_id = #{queryForm.repairPlantId}


    and DATE_FORMAT(vr.repair_date, '%Y-%m-%d') >= #{queryForm.createStartTime}


    and DATE_FORMAT(vr.repair_date, '%Y-%m-%d') <= #{queryForm.createEndTime}


    ORDER BY vr.create_time DESC

SELECT
module_id vehicleId,
IFNULL(SUM( repair_amount),0) amount
from t_repair m
LEFT JOIN t_repair_content mc ON mc.repair_id = m.repair_id
where deleted_flag = #{queryForm.deletedFlag}
and module_type = #{moduleType}
and DATE_FORMAT(m.create_time, '%Y-%m-%d') >= #{queryForm.startTime}
and DATE_FORMAT(m.create_time, '%Y-%m-%d') <= #{queryForm.endTime}
and m.enterprise_id = #{queryForm.enterpriseId}
and module_id in

    #{item}

GROUP BY module_id
